def catalan_numbers(count):
    if count <= 0:
        return

    # C_0
    current_catalan = 1
    yield current_catalan

    # Calculate C_n using the recurrence relation C_n = C_{n-1} * (2 * (2n - 1)) / (n + 1)
    for n in range(1, count):
        current_catalan = current_catalan * (2 * (2 * n - 1)) // (n + 1)
        yield current_catalan
